{
  "sentences": [
    {
      "text": "我每天中午吃午餐。",
      "pinyin": "Wǒ měitiān zhōngwǔ chī wǔcān.",
      "pinyin_numeric": "wo3 mei3tian1 zhong1wu3 chi1 wu3can1",
      "translation_en": "I eat lunch every day at noon.",
      "translation_ko": "저는 매일 점심에 점심을 먹습니다."
    },
    {
      "text": "他每天晚上看電視。",
      "pinyin": "Tā měitiān wǎnshàng kàn diànshì.",
      "pinyin_numeric": "ta1 mei3tian1 wan3shang4 kan4 dian4shi4",
      "translation_en": "He watches TV every evening.",
      "translation_ko": "그는 매일 저녁에 텔레비전을 봅니다."
    },
    {
      "text": "我們每天上午上班。",
      "pinyin": "Wǒmen měitiān shàngwǔ shàngbān.",
      "pinyin_numeric": "wo3men5 mei3tian1 shang4wu3 shang4ban1",
      "translation_en": "We go to work every morning.",
      "translation_ko": "우리는 매일 오전에 출근합니다."
    },
    {
      "text": "她每天下午下課。",
      "pinyin": "Tā měitiān xiàwǔ xiàkè.",
      "pinyin_numeric": "ta1 mei3tian1 xia4wu3 xia4ke4",
      "translation_en": "She finishes class every afternoon.",
      "translation_ko": "그녀는 매일 오후에 수업이 끝납니다."
    },
    {
      "text": "我每天晚上睡覺。",
      "pinyin": "Wǒ měitiān wǎnshàng shuìjiào.",
      "pinyin_numeric": "wo3 mei3tian1 wan3shang4 shui4jiao4",
      "translation_en": "I sleep every night.",
      "translation_ko": "저는 매일 밤에 잡니다."
    },
    {
      "text": "你每天幾點起床？",
      "pinyin": "Nǐ měitiān jǐ diǎn qǐchuáng?",
      "pinyin_numeric": "ni3 mei3tian1 ji3 dian3 qi3chuang2",
      "translation_en": "What time do you get up every day?",
      "translation_ko": "당신은 매일 몇 시에 일어납니까?"
    },
    {
      "text": "他每天下午散步。",
      "pinyin": "Tā měitiān xiàwǔ sànbù.",
      "pinyin_numeric": "ta1 mei3tian1 xia4wu3 san4bu4",
      "translation_en": "He takes a walk every afternoon.",
      "translation_ko": "그는 매일 오후에 산책합니다."
    },
    {
      "text": "我們每天中午休息。",
      "pinyin": "Wǒmen měitiān zhōngwǔ xiūxí.",
      "pinyin_numeric": "wo3men5 mei3tian1 zhong1wu3 xiu1xi2",
      "translation_en": "We rest every noon.",
      "translation_ko": "우리는 매일 점심에 휴식합니다."
    },
    {
      "text": "她每天晚上聽音樂。",
      "pinyin": "Tā měitiān wǎnshàng tīng yīnyuè.",
      "pinyin_numeric": "ta1 mei3tian1 wan3shang4 ting1 yin1yue4",
      "translation_en": "She listens to music every evening.",
      "translation_ko": "그녀는 매일 저녁에 음악을 듣습니다."
    },
    {
      "text": "我每天上午看書。",
      "pinyin": "Wǒ měitiān shàngwǔ kàn shū.",
      "pinyin_numeric": "wo3 mei3tian1 shang4wu3 kan4 shu1",
      "translation_en": "I read books every morning.",
      "translation_ko": "저는 매일 오전에 책을 봅니다."
    }
  ]
}
